import { defineConfig } from "@tanstack/start/config";

export default defineConfig({
  server: {
    port: 8234,
  },
});

{
  "compilerOptions": {
    "target": "ES2022",
    "moduleDetection": "force",
    "jsx": "react-jsx",
    "lib": ["ES2022", "DOM", "DOM.Iterable"],
    "module": "ESNext",
    "moduleResolution": "Bundler",
    "resolveJsonModule": true,
    "allowImportingTsExtensions": true,
    "verbatimModuleSyntax": true,
    "noEmit": true,
    "strict": true,
    "skipLibCheck": true,
    "paths": {
      "~/*": ["./app/*"]
    }
  }
}

import { createRouter as createTanStackRouter } from "@tanstack/react-router";
import { routeTree } from "./routeTree.gen";

export function createRouter() {
  const router = createTanStackRouter({
    routeTree,
    scrollRestoration: true,
  });

  return router;
}

declare module "@tanstack/react-router" {
  interface Register {
    router: ReturnType<typeof createRouter>;
  }
}

import { StartClient } from "@tanstack/start";
import { createRouter } from "./router";
import { hydrateRoot } from "react-dom/client";

const router = createRouter();

hydrateRoot(document, <StartClient router={router} />);

import {
  createStartHandler,
  defaultStreamHandler,
} from "@tanstack/start/server";
import { createRouter } from "./router";

export default createStartHandler({
  createRouter,
})(defaultStreamHandler);

import {
  createRootRoute,
  HeadContent,
  Outlet,
  Scripts,
} from "@tanstack/react-router";
import type { ReactNode } from "react";

export const Route = createRootRoute({
  head: () => ({
    meta: [
      {
        charSet: "utf-8",
      },
      {
        name: "viewport",
        content: "width=device-width, initial-scale=1",
      },
      {
        title: "TanStack Counter App",
      },
    ],
  }),
  component: RootComponent,
});

function RootComponent() {
  return (
    <RootDocument>
      <Outlet />
    </RootDocument>
  );
}

function RootDocument({ children }: Readonly<{ children: ReactNode }>) {
  return (
    <html>
      <head>
        <HeadContent />
      </head>
      <body>
        {children}
        <Scripts />
      </body>
    </html>
  );
}

import { createFileRoute } from "@tanstack/react-router";
import { createServerFn } from "@tanstack/start";
import { useState } from "react";

// In-memory counter state on the server
let count = 0;

// Server function to get the current count
const getCount = createServerFn({ method: "GET" }).handler(() => {
  return count;
});

// Server function to increment the counter
const incrementCount = createServerFn({ method: "POST" }).handler(() => {
  count += 1;
  return count;
});

export const Route = createFileRoute("/")({
  loader: async () => {
    const initialCount = await getCount();
    return { initialCount };
  },
  component: Home,
});

function Home() {
  const { initialCount } = Route.useLoaderData();
  const [currentCount, setCurrentCount] = useState(initialCount);

  const handleIncrement = async () => {
    const newCount = await incrementCount();
    setCurrentCount(newCount);
  };

  return (
    <div style={{ fontFamily: "sans-serif", padding: "2rem" }}>
      <h1>TanStack Start Counter</h1>
      <p>Count: {currentCount}</p>
      <button onClick={handleIncrement}>Increment</button>
    </div>
  );
}

